(function(global){'use strict';const instances=new Map();class Chart{constructor(canvas,config){this.canvas=canvas;this.ctx=canvas.getContext('2d');this.config=config;this.data=config.data||{labels:[],datasets:[]};this.options=config.options||{};this.type=config.type||'bar';this._render()}static get instances(){return instances}static register(){return this}_render(){const ctx=this.ctx;const w=this.canvas.width=this.canvas.parentElement?this.canvas.parentElement.clientWidth:800;const h=this.canvas.height=this.options?.plugins?.legend?300:200;ctx.clearRect(0,0,w,h);ctx.fillStyle=getComputedStyle(document.documentElement).getPropertyValue('--yt-text')||'#fff';ctx.font='12px system-ui,sans-serif';ctx.textAlign='center';if(this.type==='line'||this.type==='bar'){this._renderChart(ctx,w,h)}else if(this.type==='doughnut'||this.type==='pie'){this._renderDoughnut(ctx,w,h)}else{ctx.fillText('Chart.js stub - Install full library for charts',w/2,h/2)}}_renderChart(ctx,w,h){const padding={top:20,right:20,bottom:40,left:50};const chartW=w-padding.left-padding.right;const chartH=h-padding.top-padding.bottom;ctx.strokeStyle='rgba(255,255,255,0.1)';ctx.lineWidth=1;for(let i=0;i<=4;i++){const y=padding.top+chartH*(i/4);ctx.beginPath();ctx.moveTo(padding.left,y);ctx.lineTo(w-padding.right,y);ctx.stroke()}const datasets=this.data.datasets||[];const labels=this.data.labels||[];const maxVal=Math.max(...datasets.flatMap(d=>d.data||[]),1);datasets.forEach((ds,dataIndex)=>{const data=ds.data||[];const color=ds.borderColor||ds.backgroundColor||['#FF0000','#0d6efd','#198754','#ffc107','#dc3545'][dataIndex%5];ctx.strokeStyle=color;ctx.lineWidth=2;ctx.beginPath();data.forEach((val,i)=>{const x=padding.left+(chartW/(Math.max(data.length-1,1)))*i;const y=padding.top+chartH-(val/maxVal)*chartH;if(i===0)ctx.moveTo(x,y);else ctx.lineTo(x,y)});ctx.stroke();if(this.type==='bar'){const barW=chartW/data.length*.6/datasets.length;data.forEach((val,i)=>{const x=padding.left+(chartW/data.length)*i+(chartW/data.length*.2)+barW*dataIndex;const barH=(val/maxVal)*chartH;ctx.fillStyle=ds.backgroundColor||color;ctx.globalAlpha=0.8;ctx.fillRect(x,padding.top+chartH-barH,barW,barH);ctx.globalAlpha=1})}});ctx.fillStyle=getComputedStyle(document.documentElement).getPropertyValue('--yt-text-muted')||'#888';ctx.font='11px system-ui,sans-serif';ctx.textAlign='center';labels.forEach((label,i)=>{const x=padding.left+(chartW/Math.max(labels.length-1,1))*i;ctx.fillText(label,x,h-10)})}_renderDoughnut(ctx,w,h){const cx=w/2;const cy=h/2;const radius=Math.min(w,h)/2-20;const innerRadius=radius*.6;const data=this.data.datasets?.[0]?.data||[];const colors=this.data.datasets?.[0]?.backgroundColor||['#FF0000','#0d6efd','#198754','#ffc107','#dc3545','#0dcaf0','#6f42c1','#fd7e14'];const total=data.reduce((a,b)=>a+b,0);let startAngle=-Math.PI/2;data.forEach((val,i)=>{const sliceAngle=(val/total)*Math.PI*2;ctx.beginPath();ctx.moveTo(cx+innerRadius*Math.cos(startAngle),cy+innerRadius*Math.sin(startAngle));ctx.arc(cx,cy,radius,startAngle,startAngle+sliceAngle);ctx.arc(cx,cy,innerRadius,startAngle+sliceAngle,startAngle,true);ctx.closePath();ctx.fillStyle=colors[i%colors.length];ctx.fill();startAngle+=sliceAngle});const labels=this.data.labels||[];ctx.font='11px system-ui,sans-serif';ctx.textAlign='left';labels.forEach((label,i)=>{const x=w-140;const y=20+i*20;ctx.fillStyle=colors[i%colors.length];ctx.fillRect(x,y-8,12,12);ctx.fillStyle=getComputedStyle(document.documentElement).getPropertyValue('--yt-text')||'#fff';ctx.fillText(label+' ('+data[i]+')',x+18,y+1)})}update(){this._render()}destroy(){instances.delete(this.canvas)}}global.Chart=Chart})(typeof window!=='undefined'?window:this);
